// portal-a11-cargar-gasto-interno__TEST - validar_firma_ts_rol (ESCRITURA / A11) v1.
// Clonado del molde a07 (HMAC sobre buffer crudo, timing-safe, ventana ts, raw body
// binario con fallback, assert por prefijo __PEGAR_). A11 (D-C-55 / D-C-56):
//   - EXPECTED_ACTION = 'cargar.gasto_interno'.
//   - nonce DERIVADO de la firma ESPERADA recomputada y normalizada (D-C-56,
//     microcorr. 1): nonce = expectedHex.toLowerCase(). NO del header crudo, NO del body.
//   - idempotency_key con formato estricto ^[A-Za-z0-9_-]{8,64}$ (microcorr. 2).
//   - payload de negocio REJECT-UNKNOWN + tipos + 2 enums (clase, pagador_tipo); la
//     coherencia (clase x zona/cabana, pagador, comentario, horas) la validan las 18
//     constraints de gastos_internos dentro de la funcion.
const crypto = require('crypto');

const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('VITA_HMAC_SECRET no configurado (assert por prefijo, L-C-10).');
}

const ROLES_OK     = ['vicky','socio'];
const ENUM_ACTOR   = ['vicky','franco','rodrigo','remo'];
const ENUM_CLASE   = ['A','C','D','E'];
const ENUM_PAGADOR = ['socio','caja'];
const EXPECTED_ACTION = 'cargar.gasto_interno';
const IDEM_RE = /^[A-Za-z0-9_-]{8,64}$/;
const MAXLEN = 1000;

function rej(motivo, body) {
  body = body || {};
  return [{ json: { ok_firma:false, motivo, ambiente_esperado: body.ambiente_esperado ?? null,
    rol: body.rol ?? null, action: body.action ?? null, ts: (typeof body.ts!=='undefined'?body.ts:null),
    actor: body.actor ?? null, idempotency_key: body.idempotency_key ?? null, nonce: null, payload: null } }];
}

const item = $input.first();
const wh = item.json;

// 1) Raw body Buffer exacto (binario 'data' prioridad; fallback rawBody, L-C-05).
let buf = null;
try { if (item.binary && item.binary.data) buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) { buf = null; }
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) return rej('raw_body_ausente', {});

// 2) Firma HMAC recomputada sobre los mismos bytes (hex en minuscula).
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';
const expectedHex = crypto.createHmac('sha256', SECRET).update(buf).digest('hex');
const expected = 'sha256=' + expectedHex;
let firmaOk = false;
try { const a = Buffer.from(sigHeader); const b = Buffer.from(expected); firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b); } catch (e) { firmaOk = false; }
if (!firmaOk) return rej('firma_invalida', {});

// 3) nonce = firma ESPERADA calculada y normalizada (D-C-56, microcorr. 1).
const nonce = expectedHex.toLowerCase();

// 4) Parseo (firma ya validada).
let body;
try { body = JSON.parse(buf.toString('utf8')); } catch (e) { return rej('payload_invalido', {}); }

// 5) Ventana ts +-300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) return rej('ts_fuera_de_ventana', body);

// 6) Rol allowlist (D-C-39).
if (!ROLES_OK.includes(body.rol)) return rej('rol_no_permitido', body);
// 7) Action binding (D-C-41).
if (body.action !== EXPECTED_ACTION) return rej('accion_desconocida', body);
// 8) actor (sobre firmado; persona, no rol).
if (typeof body.actor !== 'string' || !ENUM_ACTOR.includes(body.actor)) return rej('payload_invalido', body);
// 9) idempotency_key formato estricto (D-C-56, microcorr. 2).
if (typeof body.idempotency_key !== 'string' || !IDEM_RE.test(body.idempotency_key)) return rej('payload_invalido', body);

// 10) Payload de negocio: REJECT-UNKNOWN + tipos + 2 enums. Coherencia -> funcion.
const p = body.payload;
if (!p || typeof p !== 'object' || Array.isArray(p)) return rej('payload_invalido', body);
const PERMITIDAS = ['fecha','periodo','clase','clase_sugerida','etiqueta','monto',
  'id_zona','id_cabana','pagador_tipo','id_socio_pagador','medio_pago','comentario','comprobante_url'];
for (const k of Object.keys(p)) { if (!PERMITIDAS.includes(k)) return rej('payload_invalido', body); }

const isStr = (v) => typeof v === 'string';
const okLen = (v) => v.length <= MAXLEN;
const isYMD = (s) => {
  if (!isStr(s) || !/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
  const Y=+s.slice(0,4), M=+s.slice(5,7), D=+s.slice(8,10);
  if (M<1||M>12||D<1||D>31) return false;
  const dt=new Date(Date.UTC(Y,M-1,D));
  return dt.getUTCFullYear()===Y && dt.getUTCMonth()===M-1 && dt.getUTCDate()===D;
};
const isPosInt = (v) => typeof v==='number' && Number.isSafeInteger(v) && v>0;

if (!isYMD(p.fecha)) return rej('payload_invalido', body);
if (p.periodo != null && !isYMD(p.periodo)) return rej('payload_invalido', body);
if (!isStr(p.clase) || !ENUM_CLASE.includes(p.clase)) return rej('payload_invalido', body);
if (p.clase_sugerida != null && (!isStr(p.clase_sugerida) || !ENUM_CLASE.includes(p.clase_sugerida))) return rej('payload_invalido', body);
if (!isStr(p.etiqueta) || p.etiqueta.trim()==='' || !okLen(p.etiqueta)) return rej('payload_invalido', body);
if (typeof p.monto !== 'number' || !Number.isFinite(p.monto) || p.monto <= 0) return rej('payload_invalido', body);
if (p.id_zona != null && !isPosInt(p.id_zona)) return rej('payload_invalido', body);
if (p.id_cabana != null && !isPosInt(p.id_cabana)) return rej('payload_invalido', body);
if (!isStr(p.pagador_tipo) || !ENUM_PAGADOR.includes(p.pagador_tipo)) return rej('payload_invalido', body);
if (p.id_socio_pagador != null && !isPosInt(p.id_socio_pagador)) return rej('payload_invalido', body);
for (const k of ['medio_pago','comentario','comprobante_url']) {
  if (p[k] != null && (!isStr(p[k]) || !okLen(p[k]))) return rej('payload_invalido', body);
}

// payloadWL: null/undefined = ausente; numeros van como numero (la funcion castea con
// ($1::jsonb)->>'campo'::tipo; monto -> numeric(12,2) en la funcion).
const payloadWL = {
  fecha: p.fecha,
  periodo: (p.periodo != null ? p.periodo : null),
  clase: p.clase,
  clase_sugerida: (p.clase_sugerida != null ? p.clase_sugerida : null),
  etiqueta: p.etiqueta.trim(),
  monto: p.monto,
  id_zona: (p.id_zona != null ? p.id_zona : null),
  id_cabana: (p.id_cabana != null ? p.id_cabana : null),
  pagador_tipo: p.pagador_tipo,
  id_socio_pagador: (p.id_socio_pagador != null ? p.id_socio_pagador : null),
  medio_pago: (p.medio_pago != null ? p.medio_pago.trim() : null),
  comentario: (p.comentario != null ? p.comentario.trim() : null),
  comprobante_url: (p.comprobante_url != null ? p.comprobante_url.trim() : null)
};

return [{ json: { ok_firma:true, motivo:null, ambiente_esperado: body.ambiente_esperado ?? null,
  rol: body.rol, action: body.action, ts, actor: body.actor,
  idempotency_key: body.idempotency_key, nonce, payload: payloadWL } }];

// portal-a11-cargar-gasto-interno__TEST - verificar_acceso (ambiente + envelope de rechazo).
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;
function envErr(code, message, detail) { return [{ json: { ok:false, error: { code, message, detail: detail ?? null } } }]; }
if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'payload invalido (campos de negocio, actor o idempotency_key)',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}
if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}
return [{ json: { ok:true } }];

// portal-a11-cargar-gasto-interno__TEST - Code: derivar.
// Arma el jsonb para portal_cargar_gasto_interno: payload de negocio + control
// server-side (actor/rol/nonce/request_ts) + idempotency_key. source_event y
// creado_por NO se mandan: los deriva la funcion ('portal_a11_'||idempotency_key ; =actor).
const v = $('validar_firma_ts_rol').first().json;
const idem = v.idempotency_key;
const fnPayload = Object.assign({}, v.payload, {
  idempotency_key: idem,
  actor: v.actor,
  rol: v.rol,
  nonce: v.nonce,
  request_ts: v.ts
});
const payload1 = JSON.stringify(fnPayload);
return [{ json: { payload1, idem, sev: 'portal_a11_' + idem } }];

// portal-a11-cargar-gasto-interno__TEST - router_cargar.
// La funcion ya devuelve el contrato final {ok,data|error} con codigos de la allowlist
// (ok idempotente/nuevo; conflicto nonce_replay/payload_mismatch/actor_mismatch;
// payload_invalido con constraint; rol_no_permitido; error_interno). Solo agregamos
// estado_incierto si el nodo PG no devolvio el contrato (fallo de dispatch; L-8D-01).
const res = $json.resultado;
const D = $('Code: derivar').first().json;
if (!res || typeof res !== 'object') {
  return [{ json: { ok:false, error: { code:'estado_incierto',
    message:'estado incierto al cargar el gasto; verificar antes de reintentar con la misma idempotency_key',
    detail: { idempotency_key: D.idem, source_event: D.sev } } } }];
}
return [{ json: res }];

// portal-a11-cargar-gasto-interno__TEST - Code: render. Punto unico de salida.
// Extrae el envelope de router; o pasa el rechazo de verificar_acceso ($json {ok:false,error}).
const e = ($json && $json.envelope) ? $json.envelope : $json;
return [{ json: e }];
